This is a bit tricky, but basically you need a custom scope. There's actually an example that is quite close to what you need, included in the tests, but here's a full example that should do what you want. Note that you will need to sprinkle some locks around if you're likely to be using this scope across threads.

```python
from contextlib import contextmanager

from injector import (Injector, InstanceProvider, Scope, ScopeDecorator,
    UnsatisfiedRequirement)


class CompanyScope(Scope):
    def configure(self):
        self.context = None
        self.companies = {}

    @contextmanager
    def __call__(self, company):
        assert self.context is None
        self.context = self.companies.setdefault(company, {})
        yield
        self.context = None

    def get(self, key, provider):
        if self.context is None:
            raise UnsatisfiedRequirement(None, key)
        try:
            return self.context[key]
        except KeyError:
            provider = InstanceProvider(provider.get(self.injector))
            self.context[key] = provider
            return provider


companyscoped = ScopeDecorator(CompanyScope)

@companyscoped
class DB(object):
    pass


class Issuer(object):
    def __init__(self, db:DB):
        print('issuer db', db)


def module(binder):
    binder.bind_scope(CompanyScope)
    company = binder.injector.get(CompanyScope)
    with company('IBM'):
        binder.bind(DB)
    with company('Microsoft'):
        binder.bind(DB)


injector = Injector(module, use_annotations=True)
company = injector.get(CompanyScope)
print('IBM')
with company('IBM'):
    injector.get(DB)
    print(injector.get(Issuer))

print()
print('Microsoft')
with company('Microsoft'):
    print(injector.get(DB))
    print(injector.get(Issuer))
```

You want to keep your main Python process alive. Either by waiting until the sub-process is finished with `join`, or with an (interruptible) busy loop:

```
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        pass
    finally:
bus.shutdown()
```

@sobolevn I have implemented this pretty simple solution to do this. What do you think? 

```python
from random import Random


class Choice(object):
    def __init__(self, seed=None):
        self.random = Random()
        if seed is not None:
            self.random.seed = seed

    def __call__(self, mode='choice', items=None, number: int = 1) -> list:
        if mode == 'multiple_choice':
            return [self.random.choice(items) for _ in range(number)]
        return self.random.choice(items)

choice = Choice()
```

Result:

```python
>>> choice('multiple_choice', items=['a', 'b', 'c'], number=2)
['c', 'c']

>>> choice('multiple_choice', items=['a', 'b', 'c'])
['a']

>>> choice('multiple_choice', items=['a', 'b', 'c'])
'b'
```

