the minimum model tweaks (once commit above merged) to get it working were less than I expected 

```python
class ProductAttribute(AbstractProductAttribute):
    def _validate_multi_option(self, value):
        for sub_value in value:
            self._validate_option(sub_value)


class ProductAttributeValue(AbstractProductAttributeValue):
    class Meta(AbstractProductAttributeValue.Meta):
        unique_together = ()

    value_multi_option = models.ManyToManyField(
        'catalogue.AttributeOption',
        blank=True, null=True,
        verbose_name=_("Value multi-option"),
        related_name='productattributemultivalue_set'
    )

    def _get_value(self):
        value = super(ProductAttributeValue, self)._get_value()
        if isinstance(value, models.Manager):
            value = value.all()
        return value

    def _set_value(self, new_value):
        super(ProductAttributeValue, self)._set_value(new_value)

    value = property(_get_value, _set_value)

    @property
    def _multi_option_as_text(self):
        return ', '.join(str(val) for val in self.value)
```

